pub(crate) fn is_pipeable(&self) -> bool {
        match self {
            // Pipeable: primary input is a function name.
            BatchCmd::Blame { .. }
            | BatchCmd::Callers { .. }
            | BatchCmd::Callees { .. }
            | BatchCmd::Deps { .. }
            | BatchCmd::Explain { .. }
            | BatchCmd::Similar { .. }
            | BatchCmd::Impact { .. }
            | BatchCmd::TestMap { .. }
            | BatchCmd::Related { .. }
            | BatchCmd::Scout { .. } => true,
            // Not pipeable: queries, paths, git refs, or no positional arg.
            BatchCmd::Search { .. }
            | BatchCmd::Gather { .. }
            | BatchCmd::Trace { .. }
            | BatchCmd::Dead { .. }
            | BatchCmd::Context { .. }
            | BatchCmd::Stats
            | BatchCmd::Onboard { .. }
            | BatchCmd::Where { .. }
            | BatchCmd::Read { .. }
            | BatchCmd::Stale { .. }
            | BatchCmd::Health
            | BatchCmd::Drift { .. }
            | BatchCmd::Notes { .. }
            | BatchCmd::Task { .. }
            | BatchCmd::Review { .. }
            | BatchCmd::Ci { .. }
            | BatchCmd::Diff { .. }
            | BatchCmd::ImpactDiff { .. }
            | BatchCmd::Plan { .. }
            | BatchCmd::Suggest { .. }
            | BatchCmd::Gc
            | BatchCmd::Refresh
            | BatchCmd::Help => false,
        }
    }

