pub fn embed_documents(&self, texts: &[&str]) -> Result<Vec<Embedding>, EmbedderError> {
        let _span = tracing::info_span!("embed_documents", count = texts.len()).entered();
        let prefix = &self.model_config.doc_prefix;
        let max_batch: usize = std::env::var("CQS_EMBED_BATCH_SIZE")
            .ok()
            .and_then(|v| v.parse().ok())
            .filter(|&n: &usize| n > 0)
            .unwrap_or(64);
        if texts.len() <= max_batch {
            let prefixed: Vec<String> = texts.iter().map(|t| format!("{}{}", prefix, t)).collect();
            return self.embed_batch(&prefixed);
        }
        let mut all = Vec::with_capacity(texts.len());
        for chunk in texts.chunks(max_batch) {
            let prefixed: Vec<String> = chunk.iter().map(|t| format!("{}{}", prefix, t)).collect();
            all.extend(self.embed_batch(&prefixed)?);
        }
        Ok(all)
    }

fn is_structural_query(query: &str) -> bool {
    // Structural patterns like "functions that return"
    if STRUCTURAL_PATTERNS_AC.is_match(query) {
        return true;
    }
    // Contains structural keywords as NL words (not identifiers)
    // e.g., "find all structs" but not "MyStruct"
    STRUCTURAL_KEYWORDS
        .iter()
        .any(|kw| query.contains(&format!(" {} ", kw)) || query.starts_with(&format!("{} ", kw)))
}

fn classify(description: &str) -> usize {
    let lower = description.to_lowercase();
    let mut best_idx = TEMPLATES
        .iter()
        .position(|e| e.template.name == "Fix a Bug")
        .unwrap_or(0);
    let mut best_score = 0.0f32;

    for (i, entry) in TEMPLATES.iter().enumerate() {
        let mut score = 0.0f32;
        for &(keyword, weight) in entry.keywords {
            if lower.contains(keyword) {
                score += weight;
            }
        }
        if score > best_score {
            best_score = score;
            best_idx = i;
        }
    }

    best_idx
}

