pub fn callable_sql_list() -> String {
        Self::ALL
            .iter()
            .filter(|ct| ct.is_callable())
            .map(|ct| {
                let s = ct.to_string();
                // SEC-13: Guard against SQL injection if a future variant name contains quotes
                debug_assert!(!s.contains('\''), "ChunkType display contains quote: {s}");
                format!("'{}'", s)
            })
            .collect::<Vec<_>>()
            .join(",")
    }

pub(crate) fn get_call_query(
        &self,
        language: Language,
    ) -> Result<&tree_sitter::Query, ParserError> {
        let cell = self.call_queries.get(&language).ok_or_else(|| {
            ParserError::QueryCompileFailed(format!("{}_calls", language), "not found".into())
        })?;

        cell.get_or_try_init(|| {
            let grammar = language.try_grammar().ok_or_else(|| {
                ParserError::QueryCompileFailed(
                    format!("{}_calls", language),
                    "no tree-sitter grammar".into(),
                )
            })?;
            let pattern = language.call_query_pattern();
            tree_sitter::Query::new(&grammar, pattern).map_err(|e| {
                ParserError::QueryCompileFailed(format!("{}_calls", language), format!("{}", e))
            })
        })
    }

async fn migrate_v16_to_v17(conn: &mut SqliteConnection) -> Result<(), StoreError> {
    let _span = tracing::info_span!("migrate_v16_to_v17").entered();

    sqlx::query(
        "CREATE TABLE IF NOT EXISTS sparse_vectors (
            chunk_id TEXT NOT NULL,
            token_id INTEGER NOT NULL,
            weight REAL NOT NULL,
            PRIMARY KEY (chunk_id, token_id)
        )"
    ).execute(&mut *conn).await?;

    sqlx::query(
        "CREATE INDEX IF NOT EXISTS idx_sparse_token ON sparse_vectors(token_id)"
    ).execute(&mut *conn).await?;

    // RT-DATA-2: enrichment idempotency marker
    sqlx::query(
        "ALTER TABLE chunks ADD COLUMN enrichment_version INTEGER NOT NULL DEFAULT 0"
    ).execute(&mut *conn).await?;

    tracing::info!("Migrated to v17: sparse_vectors table + enrichment_version column");
    Ok(())
}

