pub(crate) fn dispatch_line(&self, line: &str, out: &mut impl std::io::Write) {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            return;
        }
        let tokens = match shell_words::split(trimmed) {
            Ok(t) => t,
            Err(e) => {
                let err = serde_json::json!({"error": format!("Parse error: {e}")});
                let _ = write_json_line(out, &err);
                return;
            }
        };
        if tokens.is_empty() {
            return;
        }
        self.check_idle_timeout();
        match commands::BatchInput::try_parse_from(&tokens) {
            Ok(input) => match commands::dispatch(self, input.cmd) {
                Ok(value) => {
                    let _ = write_json_line(out, &value);
                }
                Err(e) => {
                    // EH-12: use anyhow chain formatter (`:#`) so the real
                    // root cause (e.g. CUDA OOM) surfaces to daemon clients
                    // instead of the flattened top-level "embedding failed".
                    let err = serde_json::json!({"error": format!("{e:#}")});
                    let _ = write_json_line(out, &err);
                }
            },
            Err(e) => {
                let err = serde_json::json!({"error": format!("{e:#}")});
                let _ = write_json_line(out, &err);
            }
        }
    }

fn l2_normalize_zero_vector_no_panic() {
    use ndarray::Array2;
    let mut matrix = Array2::<f32>::zeros((2, 4));
    // Row 0: zero vector
    // Row 1: normal vector
    matrix[[1, 0]] = 1.0;
    matrix[[1, 1]] = 0.0;
    matrix[[1, 2]] = 0.0;
    matrix[[1, 3]] = 0.0;

    for i in 0..2 {
        let norm = matrix.row(i).mapv(|x| x * x).sum().sqrt();
        if norm > 0.0 {
            matrix.row_mut(i).mapv_inplace(|x| x / norm);
        }
    }

    // Zero row stays zero, normalized row has unit norm
    assert_eq!(matrix[[0, 0]], 0.0);
    assert!((matrix[[1, 0]] - 1.0).abs() < 1e-6);
}

def stratify(chunks: list[dict], n: int, seed: int = 0) -> list[dict]:
    """Pick n chunks with roughly balanced language coverage."""
    rng = random.Random(seed)
    by_lang: dict[str, list[dict]] = defaultdict(list)
    for c in chunks:
        by_lang[c["language"]].append(c)
    langs = list(by_lang.keys())
    rng.shuffle(langs)
    picked: list[dict] = []
    # Round-robin across languages.
    cursor = {lang: 0 for lang in langs}
    idx_lang = {lang: 0 for lang in langs}
    for lang in langs:
        rng.shuffle(by_lang[lang])
    while len(picked) < n and langs:
        progress = False
        for lang in langs:
            if idx_lang[lang] < len(by_lang[lang]):
                picked.append(by_lang[lang][idx_lang[lang]])
                idx_lang[lang] += 1
                progress = True
                if len(picked) >= n:
                    break
        if not progress:
            break
    return picked

